//region 1. Data Models for Payment Module

/**
 * Represents the result of any payment-related operation.
 * Encapsulates success data or error information.
 */
sealed class PaymentResult<out T> {
    data class Success<out T>(val data: T) : PaymentResult<T>()
    data class Error(val exception: Throwable, val message: String? = null) : PaymentResult<Nothing>()
    object Loading : PaymentResult<Nothing>()
}

/**
 * Represents a single product available for in-app purchase.
 */
data class AppProduct(
    val productId: String,
    val name: String,
    val description: String,
    val price: String, // Formatted price (e.g., "$1.99")
    val productType: String // "inapp" or "subs"
)

/**
 * Represents an item purchased via Google Play Billing.
 * Simplified for internal app use. Full Google Purchase object has more details.
 */
data class VerifiedPurchase(
    val purchaseToken: String,
    val orderId: String?,
    val productId: String,
    val purchaseTime: Long,
    val acknowledged: Boolean
)

/**
 * Represents a transaction within the app's internal wallet.
 */
data class WalletTransaction(
    val transactionId: String,
    val userId: String,
    val type: TransactionType,
    val amount: Double,
    val currency: String,
    val timestamp: Long,
    val description: String? = null,
    val status: TransactionStatus
)

enum class TransactionType {
    DEPOSIT, WITHDRAWAL, PURCHASE, REFUND
}

enum class TransactionStatus {
    PENDING, COMPLETED, FAILED, REFUNDED
}

/**
 * Request body for verifying Google Play purchases on the backend.
 */
data class VerifyPurchaseRequest(
    val purchaseToken: String,
    val productId: String,
    val userId: String
)

/**
 * Response from backend after successful purchase verification.
 * Could include updated wallet balance or confirmation of item delivery.
 */
data class VerifyPurchaseResponse(
    val success: Boolean,
    val message: String,
    val verifiedPurchase: VerifiedPurchase?,
    val newWalletBalance: Double?
)

/**
 * Request body for performing a wallet transaction.
 */
data class WalletTransactionRequest(
    val userId: String,
    val type: TransactionType,
    val amount: Double,
    val currency: String,
    val description: String? = null
)

/**
 * Response from backend after a wallet transaction.
 */
data class WalletTransactionResponse(
    val success: Boolean,
    val message: String,
    val transaction: WalletTransaction?,
    val newWalletBalance: Double?
)

data class WalletBalanceResponse(
    val userId: String,
    val balance: Double,
    val currency: String
)

