//region 2. Backend API Service

/**
 * Interface for interacting with a secure backend.
 * All sensitive operations and purchase verifications should happen server-side.
 * Replace with your actual backend API endpoints and Retrofit setup.
 */
interface BackendApiService {

    // --- Google Play Billing Verification ---
    @POST("api/payments/google-play/verify")
    suspend fun verifyGooglePlayPurchase(@Body request: VerifyPurchaseRequest): VerifyPurchaseResponse

    // --- Wallet Management ---
    @GET("api/wallet/{userId}/balance")
    suspend fun getWalletBalance(@Path("userId") userId: String): WalletBalanceResponse

    @POST("api/wallet/transaction")
    suspend fun performWalletTransaction(@Body request: WalletTransactionRequest): WalletTransactionResponse

    @GET("api/wallet/{userId}/transactions")
    suspend fun getWalletHistory(@Path("userId") userId: String): List<WalletTransaction>

    companion object {
        private const val BASE_URL = "https://your-secure-backend.com/" // !!! IMPORTANT: Replace with your actual backend URL

        fun create(): BackendApiService {
            return Retrofit.Builder()
                .baseUrl(BASE_URL)
                .addConverterFactory(GsonConverterFactory.create())
                .build()
                .create(BackendApiService::class.java)
        }
    }
}

