//region 3. Google Play Billing Manager

/**
 * Manages all interactions with Google Play Billing Library.
 * Handles product queries, purchase flow, and basic purchase acknowledgement/consumption.
 * Relies on a backend for actual purchase verification to prevent fraud.
 */
class GooglePlayBillingManager(
    private val context: Context,
    private val backendApiService: BackendApiService,
    private val coroutineScope: CoroutineScope = CoroutineScope(Dispatchers.IO)
) : PurchasesUpdatedListener, BillingClientStateListener {

    private lateinit var billingClient: BillingClient
    private val productDetailsCache = mutableMapOf<String, com.android.billingclient.api.ProductDetails>()

    private val _billingSetupFinished = MutableStateFlow(false)
    val billingSetupFinished: StateFlow<Boolean> = _billingSetupFinished

    private val _purchasesFlow = MutableStateFlow<PaymentResult<VerifiedPurchase>?>(null)
    val purchasesFlow: StateFlow<PaymentResult<VerifiedPurchase>?> = _purchasesFlow

    private val _availableProducts = MutableStateFlow<PaymentResult<List<AppProduct>>>(PaymentResult.Loading)
    val availableProducts: StateFlow<PaymentResult<List<AppProduct>>> = _availableProducts

    private var currentUserId: String = "anonymous" // !!! IMPORTANT: Set actual user ID after login/authentication

    private val pendingPurchasesToProcess = CopyOnWriteArrayList<Purchase>()

    init {
        setupBillingClient()
    }

    private fun setupBillingClient() {
        billingClient = BillingClient.newBuilder(context)
            .setListener(this)
            .enablePendingPurchases()
            .build()
        connectToGooglePlayBilling()
    }

    fun connectToGooglePlayBilling() {
        if (!billingClient.isReady) {
            billingClient.startConnection(this)
        }
    }

    fun disconnectBillingClient() {
        if (billingClient.isReady) {
            billingClient.endConnection()
        }
        _billingSetupFinished.value = false
    }

    override fun onBillingSetupFinished(billingResult: BillingResult) {
        if (billingResult.responseCode == BillingClient.BillingResponseCode.OK) {
            _billingSetupFinished.value = true
            coroutineScope.launch {
                queryPurchases()
                queryProductDetails(
                    listOf("premium_item", "gem_pack_100", "subscription_monthly"), // !!! IMPORTANT: Replace with your actual product IDs
                    listOf(
                        QueryProductDetailsParams.ProductType.INAPP,
                        QueryProductDetailsParams.ProductType.SUBS
                    )
                )
            }
        } else {
            _billingSetupFinished.value = false
            _availableProducts.value = PaymentResult.Error(
                IOException("Billing setup failed: ${billingResult.debugMessage}"),
                "Failed to connect to Play Billing."
            )
            // Implement retry logic or inform user
        }
    }

    override fun onBillingServiceDisconnected() {
        _billingSetupFinished.value = false
        // Try to reconnect if the service disconnects
        connectToGooglePlayBilling()
    }

    /**
     * Queries Google Play for available products (in-app items and subscriptions).
     */
    suspend fun queryProductDetails(productIds: List<String>, productTypes: List<String>) {
        if (!_billingSetupFinished.value) {
            _availableProducts.value = PaymentResult.Error(
                IllegalStateException("Billing client not ready."),
                "Billing service not connected."
            )
            return
        }

        _availableProducts.value = PaymentResult.Loading

        val productDetailsParamsList = productTypes.flatMap { type ->
            productIds.map { productId ->
                QueryProductDetailsParams.Product.newBuilder()
                    .setProductId(productId)
                    .setProductType(type)
                    .build()
            }
        }

        val params = QueryProductDetailsParams.newBuilder()
            .setProductList(productDetailsParamsList)
            .build()

        val (billingResult, productDetailsList) = billingClient.queryProductDetails(params)

        if (billingResult.responseCode == BillingClient.BillingResponseCode.OK && productDetailsList != null) {
            productDetailsCache.clear()
            val appProducts = productDetailsList.map { productDetails ->
                productDetailsCache[productDetails.productId] = productDetails
                AppProduct(
                    productId = productDetails.productId,
                    name = productDetails.name,
                    description = productDetails.description,
                    price = productDetails.oneTimePurchaseOfferDetails?.formattedPrice
                        ?: productDetails.subscriptionOfferDetails?.firstOrNull()?.pricingPhases?.pricingPhaseList?.firstOrNull()?.formattedPrice
                        ?: "N/A",
                    productType = productDetails.productType
                )
            }
            _availableProducts.value = PaymentResult.Success(appProducts)
        } else {
            _availableProducts.value = PaymentResult.Error(
                IOException("Failed to query product details: ${billingResult.debugMessage}"),
                "Could not retrieve product list."
            )
        }
    }

    /**
     * Launches the Google Play purchase flow for a given product ID.
     */
    fun launchPurchaseFlow(activity: Activity, productId: String, productType: String) {
        if (!_billingSetupFinished.value) {
            _purchasesFlow.value = PaymentResult.Error(
                IllegalStateException("Billing client not ready."),
                "Billing service not connected."
            )
            return
        }

        val productDetails = productDetailsCache[productId]
        if (productDetails == null) {
            _purchasesFlow.value = PaymentResult.Error(
                IllegalArgumentException("Product details not found for $productId"),
                "Product not available for purchase."
            )
            return
        }

        val offerToken: String = when (productType) {
            BillingClient.ProductType.INAPP -> productDetails.oneTimePurchaseOfferDetails?.offerId
                ?: throw IllegalStateException("One-time purchase offer not found for in-app product: $productId")
            BillingClient.ProductType.SUBS -> productDetails.subscriptionOfferDetails?.firstOrNull()?.offerToken
                ?: throw IllegalStateException("Subscription offer not found for product: $productId")
            else -> throw IllegalArgumentException("Unknown product type: $productType")
        }

        val productDetailsParams = BillingFlowParams.ProductDetailsParams.newBuilder()
            .setProductDetails(productDetails)
            .setOfferToken(offerToken)
            .build()

        val flowParams = BillingFlowParams.newBuilder()
            .setProductDetailsParamsList(listOf(productDetailsParams))
            .build()

        val billingResult = billingClient.launchBillingFlow(activity, flowParams)

        if (billingResult.responseCode != BillingClient.BillingResponseCode.OK) {
            _purchasesFlow.value = PaymentResult.Error(
                IOException("Failed to launch billing flow: ${billingResult.debugMessage}"),
                "Failed to start purchase process."
            )
        }
    }

    /**
     * Callback for new purchases or changes to existing purchases.
     */
    override fun onPurchasesUpdated(billingResult: BillingResult, purchases: List<Purchase>?) {
        if (billingResult.responseCode == BillingClient.BillingResponseCode.OK && purchases != null) {
            // Add purchases to a pending list for sequential processing
            pendingPurchasesToProcess.addAll(purchases)
            processPendingPurchases()
        } else if (billingResult.responseCode == BillingClient.BillingResponseCode.USER_CANCELED) {
            _purchasesFlow.value = PaymentResult.Error(
                IOException("User canceled purchase: ${billingResult.debugMessage}"),
                "Purchase canceled by user."
            )
        } else {
            _purchasesFlow.value = PaymentResult.Error(
                IOException("Purchase error: ${billingResult.debugMessage}"),
                "An error occurred during purchase."
            )
        }
    }

    /**
     * Processes pending purchases sequentially.
     */
    private fun processPendingPurchases() = coroutineScope.launch {
        while (pendingPurchasesToProcess.isNotEmpty()) {
            val purchase = pendingPurchasesToProcess.removeAt(0)
            handlePurchase(purchase)
        }
    }

    /**
     * Handles a single purchase: verifies with backend, then acknowledges/consumes.
     * !!! IMPORTANT: Backend verification is crucial to prevent fraud.
     */
    private suspend fun handlePurchase(purchase: Purchase) {
        _purchasesFlow.value = PaymentResult.Loading

        if (purchase.purchaseState == Purchase.PurchaseState.PURCHASED) {
            try {
                // 1. Send purchase token to your secure backend for verification
                val verificationResponse = backendApiService.verifyGooglePlayPurchase(
                    VerifyPurchaseRequest(
                        purchaseToken = purchase.purchaseToken,
                        productId = purchase.products.first(), // Assuming one product per purchase
                        userId = currentUserId
                    )
                )

                if (verificationResponse.success) {
                    val verifiedPurchase = VerifiedPurchase(
                        purchaseToken = purchase.purchaseToken,
                        orderId = purchase.orderId,
                        productId = purchase.products.first(),
                        purchaseTime = purchase.purchaseTime,
                        acknowledged = purchase.isAcknowledged
                    )
                    _purchasesFlow.value = PaymentResult.Success(verifiedPurchase)

                    // 2. Acknowledge or consume the purchase after backend verification
                    if (purchase.products.firstOrNull()?.let { productDetailsCache[it]?.productType == BillingClient.ProductType.INAPP } == true) {
                        // Consumable in-app products (e.g., gems, coins)
                        val consumeParams = ConsumeParams.newBuilder()
                            .setPurchaseToken(purchase.purchaseToken)
                            .build()
                        val (consumeResult, outToken) = billingClient.consumePurchase(consumeParams)
                        if (consumeResult.responseCode == BillingClient.BillingResponseCode.OK) {
                            // Purchase consumed successfully
                        } else {
                            // Handle consumption error (e.g., retry or log)
                        }
                    } else if (!purchase.isAcknowledged) {
                        // Non-consumable in-app products or subscriptions
                        val acknowledgeParams = AcknowledgePurchaseParams.newBuilder()
                            .setPurchaseToken(purchase.purchaseToken)
                            .build()
                        val acknowledgeResult = billingClient.acknowledgePurchase(acknowledgeParams)
                        if (acknowledgeResult.responseCode == BillingClient.BillingResponseCode.OK) {
                            // Purchase acknowledged successfully
                        } else {
                            // Handle acknowledgment error (e.g., retry or log)
                        }
                    }
                } else {
                    _purchasesFlow.value = PaymentResult.Error(
                        IOException("Backend verification failed: ${verificationResponse.message}"),
                        "Purchase could not be verified by the server."
                    )
                    // Consider what to do here: refund? user support?
                }

            } catch (e: Exception) {
                _purchasesFlow.value = PaymentResult.Error(
                    e,
                    "Error during purchase verification or processing."
                )
                // Log the error, potentially try to retry verification/acknowledgement later.
                // It's critical not to lose track of unacknowledged/unconsumed purchases.
            }
        } else if (purchase.purchaseState == Purchase.PurchaseState.PENDING) {
            // Purchase is pending, await for user to complete payment.
            // UI should show a pending state or instruct the user.
            _purchasesFlow.value = PaymentResult.Error(
                IOException("Purchase is pending, awaiting payment confirmation."),
                "Purchase is pending."
            )
        }
    }

    /**
     * Queries for existing purchases that the user owns.
     * This should be done on app startup to handle unacknowledged purchases and verify subscriptions.
     */
    suspend fun queryPurchases() {
        if (!_billingSetupFinished.value) return

        val inAppPurchasesResult = billingClient.queryPurchasesAsync(
            QueryPurchasesParams.newBuilder().setProductType(BillingClient.ProductType.INAPP).build()
        )
        val subsPurchasesResult = billingClient.queryPurchasesAsync(
            QueryPurchasesParams.newBuilder().setProductType(BillingClient.ProductType.SUBS).build()
        )

        val allPurchases = mutableListOf<Purchase>()
        if (inAppPurchasesResult.billingResult.responseCode == BillingClient.BillingResponseCode.OK) {
            inAppPurchasesResult.purchasesList.forEach { purchase ->
                // Ensure purchase is processed, especially if it's not acknowledged
                if (purchase.purchaseState == Purchase.PurchaseState.PURCHASED) {
                    if (productDetailsCache[purchase.products.first()]?.productType == BillingClient.ProductType.INAPP && !purchase.isAcknowledged) {
                         // Add to pending for processing, don't consume/ack right away if backend processing is needed
                         pendingPurchasesToProcess.add(purchase)
                    } else if (productDetailsCache[purchase.products.first()]?.productType == BillingClient.ProductType.SUBS && !purchase.isAcknowledged) {
                        pendingPurchasesToProcess.add(purchase)
                    }
                }
                allPurchases.add(purchase)
            }
        }

        if (subsPurchasesResult.billingResult.responseCode == BillingClient.BillingResponseCode.OK) {
            subsPurchasesResult.purchasesList.forEach { purchase ->
                 if (purchase.purchaseState == Purchase.PurchaseState.PURCHASED && !purchase.isAcknowledged) {
                    pendingPurchasesToProcess.add(purchase)
                 }
                allPurchases.add(purchase)
            }
        }

        if (pendingPurchasesToProcess.isNotEmpty()) {
            processPendingPurchases() // Process any purchases found that need attention
        }
        // You might want to expose the list of all owned purchases
    }

    fun setCurrentUserId(userId: String) {
        this.currentUserId = userId
    }
}

