/**
 * Manages all interactions with the app's internal wallet system.
 * All wallet operations should be handled by a secure backend.
 * This class acts as a client-side interface to those backend operations.
 */
class WalletManager(
    private val backendApiService: BackendApiService,
    private val coroutineScope: CoroutineScope = CoroutineScope(Dispatchers.IO)
) {

    private val _walletBalance = MutableStateFlow<PaymentResult<WalletBalanceResponse>>(PaymentResult.Loading)
    val walletBalance: StateFlow<PaymentResult<WalletBalanceResponse>> = _walletBalance

    private val _walletTransactions = MutableStateFlow<PaymentResult<List<WalletTransaction>>>(PaymentResult.Loading)
    val walletTransactions: StateFlow<PaymentResult<List<WalletTransaction>>> = _walletTransactions

    private var currentUserId: String = "anonymous" // !!! IMPORTANT: Set actual user ID after login/authentication

    /**
     * Retrieves the current wallet balance for the authenticated user from the backend.
     */
    fun getWalletBalance() = coroutineScope.launch {
        _walletBalance.value = PaymentResult.Loading
        try {
            val response = backendApiService.getWalletBalance(currentUserId)
            _walletBalance.value = PaymentResult.Success(response)
        } catch (e: Exception) {
            _walletBalance.value = PaymentResult.Error(e, "Failed to retrieve wallet balance.")
        }
    }

    /**
     * Credits the user's wallet. Typically used after an in-app purchase (IAP) or external deposit.
     * This operation *must* be initiated and verified on the secure backend.
     */
    fun creditWallet(amount: Double, currency: String, description: String? = null) = coroutineScope.launch {
        // !!! IMPORTANT: In a real application, direct client-side crediting would be highly insecure.
        // This method would typically be called by the backend itself after verifying an IAP
        // or an external payment, or triggered by an admin tool.
        // If it's *client-initiated*, it must still go through the backend for validation.
        val request = WalletTransactionRequest(currentUserId, TransactionType.DEPOSIT, amount, currency, description)
        performWalletOperation(request)
    }

    /**
     * Debits the user's wallet. Used for in-app purchases using wallet balance.
     */
    fun debitWallet(amount: Double, currency: String, description: String? = null) = coroutineScope.launch {
        val request = WalletTransactionRequest(currentUserId, TransactionType.WITHDRAWAL, amount, currency, description)
        performWalletOperation(request)
    }

    /**
     * Performs a generic wallet transaction on the backend.
     */
    private suspend fun performWalletOperation(request: WalletTransactionRequest) {
        // Do not update _walletBalance directly here, wait for response from backend.
        // Potentially use a separate flow for transaction results.
        try {
            val response = backendApiService.performWalletTransaction(request)
            if (response.success) {
                // Optionally update wallet balance here or trigger a refresh
                response.newWalletBalance?.let {
                    _walletBalance.value = PaymentResult.Success(WalletBalanceResponse(currentUserId, it, request.currency))
                }
                // Notify of successful transaction
            } else {
                // Notify of transaction failure
            }
        } catch (e: Exception) {
            // Notify of transaction error
        }
    }

    /**
     * Retrieves the transaction history for the authenticated user from the backend.
     */
    fun getWalletHistory() = coroutineScope.launch {
        _walletTransactions.value = PaymentResult.Loading
        try {
            val transactions = backendApiService.getWalletHistory(currentUserId)
            _walletTransactions.value = PaymentResult.Success(transactions)
        } catch (e: Exception) {
            _walletTransactions.value = PaymentResult.Error(e, "Failed to retrieve wallet transactions.")
        }
    }

    fun setCurrentUserId(userId: String) {
        this.currentUserId = userId
    }
}

