//region 5. Main Payment Processor Module

/**
 * The main entry point for the payment processing module.
 * Orchestrates interactions between Google Play Billing and the internal Wallet system.
 */
class PaymentProcessor(
    context: Context,
    private val coroutineScope: CoroutineScope = CoroutineScope(Dispatchers.IO) // Or use a ViewModelScope/LifecycleScope
) {
    private val backendApiService: BackendApiService = BackendApiService.create()
    val googlePlayBillingManager: GooglePlayBillingManager = GooglePlayBillingManager(context, backendApiService, coroutineScope)
    val walletManager: WalletManager = WalletManager(backendApiService, coroutineScope)

    init {
        // Initialize managers
        googlePlayBillingManager.connectToGooglePlayBilling()
        // No explicit init needed for walletManager, its methods will fetch data on demand
    }

    fun setCurrentUserId(userId: String) {
        googlePlayBillingManager.setCurrentUserId(userId)
        walletManager.setCurrentUserId(userId)
        // Refresh wallet balance and history for the new user
        walletManager.getWalletBalance()
        walletManager.getWalletHistory()
    }

    fun release() {
        googlePlayBillingManager.disconnectBillingClient()
        coroutineScope.cancel() // Cancel any ongoing coroutines when the processor is no longer needed
    }
}

